def transform(row):
    time = row[0]
    hour, minute = time.split(':')
    hour = int(hour)
    minute = int(minute)

    if hour < 20:
        return f"{hour + 20}:00-{hour + 19}:00"
    else:
        return f"{hour - 10}:00-{hour - 1}:00"

def transform(row):
    time_str = row[0]
    hour_str, minute_str, second_str = time_str.split(':')
    hour = int(hour_str)
    minute = int(minute_str)
    second = int(second_str)

    if 6 <= hour < 12:
        return f"{hour}:00AM"
    elif 12 <= hour < 18:
        return f"{hour}:00PM"
    else:
        return f"{hour}:00PM" if hour >= 12 else f"{hour}:00AM"

def transform(row):
    time_str = row[0]

    # Parse time string into hours, minutes, seconds
    try:
        h, m, s = map(int, time_str.split(':'))
    except ValueError:
        return time_str  # Return original if parsing fails

    # Convert to 12-hour format
    if h < 12:
        am_pm = 'AM'
        hour = h
    else:
        am_pm = 'PM'
        hour = h - 12

    # Handle 12:00:00 PM case
    if hour == 0:
        hour = 12

    # Format as 'H:00AM/PM'
    return f"{hour}:00{am_pm}"

def transform(row):
    time_str = row[0]

    # Parse the time string into hours, minutes, seconds
    try:
        h, m, s = map(int, time_str.split(':'))
    except ValueError:
        return time_str  # Return original if parsing fails

    # Convert to 12-hour format
    if h >= 12:
        period = 'PM'
        h -= 12
    else:
        period = 'AM'
        if h == 0:
            h = 12
        else:
            h = h

    # Format as 'HH:MM:SS' with 12-hour format and AM/PM
    return f"{h:02d}:{m:02d}:{s:02d} {period}"

