import re
import math
import datetime
import calendar

def transform(row):
    x = row[0]

    # Check if the input is a number
    if alnum(x) and not alpha(x):
        # Check if it's a number with decimal points
        if '.' in x:
            # Try to parse as a float
            try:
                num = float(x)
                # Round to 2 decimal places
                return number_2dp(num)
            except ValueError:
                # If not a number, return as is
                return x
        else:
            # Check if it's an integer
            try:
                num = int(x)
                # Format with leading zeros if needed
                return f"{num:05d}"
            except ValueError:
                # If not a number, return as is
                return x
    else:
        # If it's not a number, return as is
        return x
